/**
 * Tests that flow collection properly propagates exceptions when the dispatcher throws
 * during dispatch (e.g., when Dispatchers.Main is not available).
 *
 * Related issue: https://github.com/JetBrains/compose-multiplatform/issues/4835
 */
class FlowOnDispatcherExceptionTest : TestBase() {

    /**
     * A dispatcher that always throws an exception when dispatch is called.
     * This simulates what happens when Dispatchers.Main.immediate is not available.
     */
    private class FailingDispatcher : CoroutineDispatcher() {
        override fun dispatch(context: CoroutineContext, block: Runnable) {
            throw TestException("Dispatcher is not available")
        }
    }

    @Test
    fun testFlowOnWithFailingDispatcher() = runTest {
        val flow = flowOf(1, 2, 3)
            .flowOn(FailingDispatcher())

        // Before the fix, this would hang silently.
        // After the fix, it should throw TestException.
        assertFailsWith<TestException> {
            flow.collect {
                println("collect: $it")
            }
        }
    }

    @Test
    fun testFlowOnWithFailingDispatcherAndBuffer() = runTest {
        val flow = flowOf(1, 2, 3)
            .buffer()
            .flowOn(FailingDispatcher())

        // Before the fix, this would hang silently.
        // After the fix, it should throw TestException.
        assertFailsWith<TestException> {
            flow.collect {
                println("collect: $it")
            }
        }
    }

    @Test
    fun testChannelFlowWithFailingDispatcher() = runTest {
        val flow = channelFlow {
            send(1)
            send(2)
            send(3)
        }.flowOn(FailingDispatcher())

        // Before the fix, this would hang silently.
        // After the fix, it should throw TestException.
        assertFailsWith<TestException> {
            flow.collect {
                println("collect: $it")
            }
        }
    }

    @Test
    fun testProduceWithFailingDispatcher() = runTest {
        // This test verifies that produce with ATOMIC start handles dispatcher exceptions correctly.
        // The produce coroutine uses ATOMIC start mode, which is what flowOn uses internally.
        assertFailsWith<TestException> {
            coroutineScope {
                val channel = produce<Int>(FailingDispatcher()) {
                    send(1)
                }
                channel.receive()
            }
        }
    }

    @Test
    fun testLaunchAtomicWithFailingDispatcher() = runTest {
        // Verify that ATOMIC start mode properly propagates dispatcher exceptions
        assertFailsWith<TestException> {
            coroutineScope {
                @OptIn(DelicateCoroutinesApi::class)
                launch(FailingDispatcher(), start = CoroutineStart.ATOMIC) {
                    println("This should not be printed")
                }
            }
        }
    }
}
"}

