 * Similar to [startCoroutineCancellable], but for already created coroutine.
 * [fatalCompletion] is used only when interception machinery throws an exception
 */
internal fun Continuation<Unit>.startCoroutineCancellable(fatalCompletion: Continuation<*>) =
    runSafely(fatalCompletion) {
        intercepted().resumeCancellableWith(Result.success(Unit))
    }

/**
 * Use this function to start coroutine atomically (without cancellation check) while
 * handling dispatcher exceptions. This is similar to [startCoroutineCancellable], but
 * the started coroutine cannot be cancelled before it starts executing.
 *
 * This is needed because [kotlin.coroutines.intrinsics.startCoroutine] does not handle
 * exceptions from the dispatcher, which can cause the coroutine to hang silently if
 * the dispatcher throws (e.g., when Dispatchers.Main is missing).
 */
internal fun <R, T> (suspend (R) -> T).startCoroutineAtomic(
    receiver: R, completion: Continuation<T>,
) = runSafely(completion) {
    createCoroutineUnintercepted(receiver, completion).intercepted().resumeWith(Result.success(Unit))
}

